
-- Kids Quest Hub Fusion schema + expanded interactive levels
-- Run this file in Supabase SQL Editor.
-- It is safe to run again: core records are upserted, old demo levels for these games are replaced.

create extension if not exists pgcrypto;

create table if not exists public.courses (
  id uuid primary key default gen_random_uuid(),
  title text not null,
  slug text not null unique,
  emoji text not null default '🎮',
  created_at timestamptz not null default now()
);

create table if not exists public.games (
  id uuid primary key default gen_random_uuid(),
  course_id uuid not null references public.courses(id) on delete cascade,
  title text not null,
  slug text not null unique,
  age_min int not null default 6,
  age_max int not null default 9,
  duration_minutes int not null default 60,
  description text,
  cover_emoji text not null default '🎮',
  is_active boolean not null default true,
  created_at timestamptz not null default now()
);

create table if not exists public.game_levels (
  id uuid primary key default gen_random_uuid(),
  game_id uuid not null references public.games(id) on delete cascade,
  order_index int not null,
  title text not null,
  type text not null default 'game',
  time_minutes int not null default 7,
  teacher_hint text,
  config_json jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  unique(game_id, order_index)
);

alter table public.game_levels drop constraint if exists game_levels_type_check;
alter table public.game_levels add constraint game_levels_type_check check (type in ('choice', 'sort', 'build', 'game', 'quiz'));

create table if not exists public.rooms (
  id uuid primary key default gen_random_uuid(),
  code text not null unique,
  game_id uuid not null references public.games(id) on delete cascade,
  teacher_name text not null default 'Викладач',
  status text not null default 'waiting' check (status in ('waiting', 'running', 'finished')),
  current_level int not null default 0,
  level_limit int not null default 15,
  timer_ends_at timestamptz,
  started_at timestamptz,
  ended_at timestamptz,
  created_at timestamptz not null default now()
);

alter table public.rooms add column if not exists level_limit int not null default 15;

create table if not exists public.teams (
  id uuid primary key default gen_random_uuid(),
  room_id uuid not null references public.rooms(id) on delete cascade,
  name text not null,
  emoji text not null default '🔵',
  score int not null default 0,
  created_at timestamptz not null default now()
);

create table if not exists public.players (
  id uuid primary key default gen_random_uuid(),
  room_id uuid not null references public.rooms(id) on delete cascade,
  team_id uuid references public.teams(id) on delete set null,
  name text not null,
  avatar text not null default '🤖',
  score int not null default 0,
  current_level int not null default 0,
  status text not null default 'online',
  joined_at timestamptz not null default now()
);

create table if not exists public.events (
  id uuid primary key default gen_random_uuid(),
  room_id uuid not null references public.rooms(id) on delete cascade,
  player_id uuid references public.players(id) on delete set null,
  type text not null,
  payload_json jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now()
);

alter table public.courses enable row level security;
alter table public.games enable row level security;
alter table public.game_levels enable row level security;
alter table public.rooms enable row level security;
alter table public.teams enable row level security;
alter table public.players enable row level security;
alter table public.events enable row level security;

drop policy if exists "open read courses" on public.courses;
drop policy if exists "open read games" on public.games;
drop policy if exists "open read levels" on public.game_levels;
drop policy if exists "open classroom rooms" on public.rooms;
drop policy if exists "open classroom teams" on public.teams;
drop policy if exists "open classroom players" on public.players;
drop policy if exists "open classroom events" on public.events;

create policy "open read courses" on public.courses for select using (true);
create policy "open read games" on public.games for select using (true);
create policy "open read levels" on public.game_levels for select using (true);
create policy "open classroom rooms" on public.rooms for all using (true) with check (true);
create policy "open classroom teams" on public.teams for all using (true) with check (true);
create policy "open classroom players" on public.players for all using (true) with check (true);
create policy "open classroom events" on public.events for all using (true) with check (true);

grant usage on schema public to anon, authenticated;
grant select, insert, update, delete on all tables in schema public to anon, authenticated;
grant usage, select on all sequences in schema public to anon, authenticated;

on conflict (slug) do update set title = excluded.title, emoji = excluded.emoji;

on conflict (slug) do update set title = excluded.title, description = excluded.description, cover_emoji = excluded.cover_emoji, duration_minutes = excluded.duration_minutes, is_active = true;

delete from public.game_levels where game_id in ('10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000002', '30000000-0000-4000-8000-000000000003');


-- Check result
select g.title, count(l.id) as levels from public.games g left join public.game_levels l on l.game_id = g.id group by g.title order by g.title;
